  const ans: number[] = [];
  for (const [li, ri, threshold] of queries) {
    const freq: { [key: string]: number } = {};
    for (let i = li; i <= ri; i++) {
      const num = nums[i];
      freq[num.toString()] = (freq[num.toString()] || 0) + 1;
